162	// The `ScheduledIo::readiness` (`AtomicUsize`) is packed full of goodness.
163	//
164	// | shutdown | driver tick | readiness |
165	// |----------+-------------+-----------|
166	// |   1 bit  |   15 bits   |  16 bits  |
167	
168	const READINESS: bit::Pack = bit::Pack::least_significant(16);
169	
170	const TICK: bit::Pack = READINESS.then(15);
171	
172	const SHUTDOWN: bit::Pack = TICK.then(1);
