176	impl Default for ScheduledIo {
177	    fn default() -> ScheduledIo {
178	        ScheduledIo {
179	            linked_list_pointers: UnsafeCell::new(linked_list::Pointers::new()),
180	            readiness: AtomicUsize::new(0),
