566	impl Drop for Readiness<'_> {
567	    fn drop(&mut self) {
568	        let mut waiters = self.scheduled_io.waiters.lock();
569	
570	        // Safety: `waiter` is only ever stored in `waiters`
571	        unsafe {
572	            waiters
573	                .list
574	                .remove(NonNull::new_unchecked(self.waiter.get()))
575	        };
576	    }
577	}
