10	// Kind of arbitrary, but buffering 16 `ScheduledIo`s doesn't seem like much
11	const NOTIFY_AFTER: usize = 16;
12	
13	pub(super) struct RegistrationSet {
14	    num_pending_release: AtomicUsize,
15	}
16	
17	pub(super) struct Synced {
18	    // True when the I/O driver shutdown. At this point, no more registrations
19	    // should be added to the set.
20	    is_shutdown: bool,
21	
22	    // List of all registrations tracked by the set
23	    registrations: LinkedList<Arc<ScheduledIo>>,
24	
25	    // Registrations that are pending drop. When a `Registration` is dropped, it
26	    // stores its `ScheduledIo` in this list. The I/O driver is responsible for
27	    // dropping it. This ensures the `ScheduledIo` is not freed while it can
28	    // still be included in an I/O event.
29	    pending_release: Vec<Arc<ScheduledIo>>,
30	}
31	
32	impl RegistrationSet {
33	    pub(super) fn new() -> (RegistrationSet, Synced) {
34	        let set = RegistrationSet {
35	            num_pending_release: AtomicUsize::new(0),
36	        };
37	
38	        let synced = Synced {
39	            is_shutdown: false,
40	            registrations: LinkedList::new(),
41	            pending_release: Vec::with_capacity(NOTIFY_AFTER),
42	        };
43	
44	        (set, synced)
45	    }
46	
47	    pub(super) fn is_shutdown(&self, synced: &Synced) -> bool {
48	        synced.is_shutdown
49	    }
50	
51	    /// Returns `true` if there are registrations that need to be released
52	    pub(super) fn needs_release(&self) -> bool {
53	        self.num_pending_release.load(Acquire) != 0
54	    }
55	
56	    pub(super) fn allocate(&self, synced: &mut Synced) -> io::Result<Arc<ScheduledIo>> {
57	        if synced.is_shutdown {
58	            return Err(io::Error::new(
59	                io::ErrorKind::Other,
60	                crate::util::error::RUNTIME_SHUTTING_DOWN_ERROR,
61	            ));
62	        }
63	
64	        let ret = Arc::new(ScheduledIo::default());
65	
66	        // Push a ref into the list of all resources.
67	        synced.registrations.push_front(ret.clone());
68	
69	        Ok(ret)
70	    }
71	
72	    // Returns `true` if the caller should unblock the I/O driver to purge
73	    // registrations pending release.
74	    pub(super) fn deregister(&self, synced: &mut Synced, registration: &Arc<ScheduledIo>) -> bool {
75	        synced.pending_release.push(registration.clone());
76	
77	        let len = synced.pending_release.len();
78	        self.num_pending_release.store(len, Release);
79	
80	        len == NOTIFY_AFTER
81	    }
82	
83	    pub(super) fn shutdown(&self, synced: &mut Synced) -> Vec<Arc<ScheduledIo>> {
84	        if synced.is_shutdown {
85	            return vec![];
86	        }
87	
88	        synced.is_shutdown = true;
89	        synced.pending_release.clear();
90	
91	        // Building a vec of all outstanding I/O handles could be expensive, but
92	        // this is the shutdown operation. In theory, shutdowns should be
93	        // "clean" with no outstanding I/O resources. Even if it is slow, we
94	        // aren't optimizing for shutdown.
95	        let mut ret = vec![];
96	
97	        while let Some(io) = synced.registrations.pop_back() {
98	            ret.push(io);
99	        }
100	
101	        ret
102	    }
103	
104	    pub(super) fn release(&self, synced: &mut Synced) {
105	        let pending = std::mem::take(&mut synced.pending_release);
106	
107	        for io in pending {
108	            // safety: the registration is part of our list
109	            unsafe { self.remove(synced, &io) }
110	        }
111	
112	        self.num_pending_release.store(0, Release);
113	    }
114	
115	    // This function is marked as unsafe, because the caller must make sure that
116	    // `io` is part of the registration set.
117	    pub(super) unsafe fn remove(&self, synced: &mut Synced, io: &Arc<ScheduledIo>) {
118	        // SAFETY: Pointers into an Arc are never null.
119	        let io = unsafe { NonNull::new_unchecked(Arc::as_ptr(io).cast_mut()) };
120	
121	        super::EXPOSE_IO.unexpose_provenance(io.as_ptr());
122	        // SAFETY: the caller guarantees that `io` is part of this list.
123	        let _ = unsafe { synced.registrations.remove(io) };
124	    }
125	}
126	
127	// Safety: `Arc` pins the inner data
128	unsafe impl linked_list::Link for Arc<ScheduledIo> {
129	    type Handle = Arc<ScheduledIo>;
130	    type Target = ScheduledIo;
131	
132	    fn as_raw(handle: &Self::Handle) -> NonNull<ScheduledIo> {
133	        // safety: Arc::as_ptr never returns null
134	        unsafe { NonNull::new_unchecked(Arc::as_ptr(handle) as *mut _) }
135	    }
136	
137	    unsafe fn from_raw(ptr: NonNull<Self::Target>) -> Arc<ScheduledIo> {
138	        // safety: the linked list currently owns a ref count
139	        unsafe { Arc::from_raw(ptr.as_ptr() as *const _) }
140	    }
141	
142	    unsafe fn pointers(
143	        target: NonNull<Self::Target>,
144	    ) -> NonNull<linked_list::Pointers<ScheduledIo>> {
145	        // safety: `target.as_ref().linked_list_pointers` is a `UnsafeCell` that
146	        // always returns a non-null pointer.
147	        unsafe { NonNull::new_unchecked(target.as_ref().linked_list_pointers.get()) }
148	    }
149	}
