  pub(super) fn wake(&self, ready: Ready) {
      let mut wakers = WakeList::new();  // Stack array for efficiency

      let mut waiters = self.waiters.lock();  // Acquire lock

      // Check AsyncRead slot (line 242-246)
      if ready.is_readable() {
          if let Some(waker) = waiters.reader.take() {
              wakers.push(waker);
          }
      }

      // Check AsyncWrite slot (line 248-253)
      if ready.is_writable() {
          if let Some(waker) = waiters.writer.take() {
              wakers.push(waker);
          }
      }

      // Drain matching waiters from LinkedList (line 255-280)
      'outer: loop {
          let mut iter = waiters.list.drain_filter(|w| ready.satisfies(w.interest));

          while wakers.can_push() {  // Stack array not full
              match iter.next() {
                  Some(waiter) => {
                      let waiter = unsafe { &mut *waiter.as_ptr() };

                      if let Some(waker) = waiter.waker.take() {
                          waiter.is_ready = true;  // Line 264
                          wakers.push(waker);
                      }
                  }
                  None => break 'outer,
              }
          }

          drop(waiters);  // Release lock before waking (line 274)
          wakers.wake_all();  // Wake current batch
          waiters = self.waiters.lock();  // Re-acquire for next batch
      }

      drop(waiters);  // Final lock release
      wakers.wake_all();  // Wake final batch
  }
  ```
  - Key design: Takes lock, collects wakers into stack buffer, releases lock, wakes
  - Prevents deadlock: wake() doesn't hold lock during waker.wake() calls

