      direction: Direction,
  ) -> Poll<ReadyEvent> {
      let curr = self.readiness.load(Acquire);  // Line 308

      let ready = direction.mask() & Ready::from_usize(READINESS.unpack(curr));
      let is_shutdown = SHUTDOWN.unpack(curr) != 0;

      if ready.is_empty() && !is_shutdown {  // Line 313: Not ready yet
          let mut waiters = self.waiters.lock();
          let waker = match direction {
              Direction::Read => &mut waiters.reader,  // Line 317
              Direction::Write => &mut waiters.writer,
          };

          // Update waker (clone_from only clones if different task)
          match waker {
              Some(waker) => waker.clone_from(cx.waker()),  // Line 324
              None => *waker = Some(cx.waker().clone()),    // Line 325
          }

          // Double-check after storing waker (lines 328-332)
          let curr = self.readiness.load(Acquire);
          let ready = direction.mask() & Ready::from_usize(READINESS.unpack(curr));
          let is_shutdown = SHUTDOWN.unpack(curr) != 0;

          if is_shutdown || !ready.is_empty() {  // Became ready while taking lock
              return Poll::Ready(ReadyEvent { tick, ready, is_shutdown });
          }

          Poll::Pending  // Line 340: Task will be woken when event arrives
      } else {
          Poll::Ready(ReadyEvent { tick, ready, is_shutdown })  // Line 349: Already ready
      }
  }
  ```
  - Stores `cx.waker()` in `waiters.reader` or `waiters.writer`
  - When event arrives, `wake()` calls `waker.wake()`

