  fn poll(self: Pin<&mut Self>, cx: &mut Context<'_>) -> Poll<Self::Output> {
      let (scheduled_io, state, waiter) = { ... };  // Unsafe borrow

      loop {
          match *state {
              State::Init => {
                  // Fast path: check if already ready (lines 445-462)
                  let curr = scheduled_io.readiness.load(SeqCst);
                  let is_shutdown = SHUTDOWN.unpack(curr) != 0;
                  let interest = unsafe { (*waiter.get()).interest };
                  let ready = Ready::from_usize(READINESS.unpack(curr)).intersection(interest);

                  if !ready.is_empty() || is_shutdown {
                      *state = State::Done;
                      return Poll::Ready(ReadyEvent { tick, ready, is_shutdown });
                  }

                  // Slow path: take lock and double-check (lines 464-486)
                  let mut waiters = scheduled_io.waiters.lock();
                  let curr = scheduled_io.readiness.load(SeqCst);

                  // ... check again ...

                  // Not ready, insert into list (lines 488-504)
                  let waker = unsafe { &mut (*waiter.get()).waker };
                  let old = waker.replace(cx.waker().clone());
                  debug_assert!(old.is_none());

                  waiters.list.push_front(unsafe { NonNull::new_unchecked(waiter.get()) });
                  *state = State::Waiting;
              }

              State::Waiting => {
                  // Poll again (lines 506-533)
                  let waiters = scheduled_io.waiters.lock();
                  let w = unsafe { &mut *waiter.get() };

                  if w.is_ready {  // Set to true by wake() (line 264)
                      *state = State::Done;
                  } else {
                      w.waker.as_mut().unwrap().clone_from(cx.waker());
                      return Poll::Pending;
                  }
                  drop(waiters);
              }

              State::Done => {
                  // Return final readiness (lines 535-559)
                  let curr = scheduled_io.readiness.load(Acquire);
                  let is_shutdown = SHUTDOWN.unpack(curr) != 0;
                  let tick = TICK.unpack(curr) as u8;
                  let interest = unsafe { (*waiter.get()).interest };
                  let ready = Ready::from_usize(READINESS.unpack(curr)).intersection(interest);

                  return Poll::Ready(ReadyEvent { tick, ready, is_shutdown });
              }
          }
      }
  }
  ```

